# .github/workflows/deploy.yml  — emit TTFD milestones to telemetry
- name: Emit staging deploy event
  if: github.ref == 'refs/heads/main'
  run: |
    curl -s -X POST "$TELEMETRY_ENDPOINT/events"       -H "Authorization: Bearer $ACME_TELEMETRY_TOKEN"       -H "Content-Type: application/json"       -d '{
        "event_type": "claude.deploy.staging",
        "properties": {
          "team_id": "${{ env.ACME_TEAM_ID }}",
          "project_id": "${{ github.repository }}",
          "sha": "${{ github.sha }}"
        }
      }'
  env:
    TELEMETRY_ENDPOINT: ${{ secrets.TELEMETRY_ENDPOINT }}
    ACME_TELEMETRY_TOKEN: ${{ secrets.ACME_TELEMETRY_TOKEN }}
